import { x402Client, x402HTTPClient } from "@x402/core/client";
import { encodePaymentSignatureHeader } from "@x402/core/http";
import { registerExactEvmScheme } from "@x402/evm/exact/client";
import { privateKeyToAccount } from "viem/accounts";

const signer = privateKeyToAccount(process.env.EVM_PRIVATE_KEY as `0x${string}`);
const client = new x402Client();
registerExactEvmScheme(client, { signer });
const http = new x402HTTPClient(client);

// Standard x402: 402 -> decode PAYMENT-REQUIRED -> sign -> retry with PAYMENT-SIGNATURE.
// (Bankr agents can use Bankr wallet signing instead -- see setup.)
async function pay(url: string, init: RequestInit = {}) {
  let res = await fetch(url, init);
  if (res.status === 402) {
    const challenge = JSON.parse(Buffer.from(res.headers.get("PAYMENT-REQUIRED")!, "base64").toString());
    const sig = encodePaymentSignatureHeader(await http.createPaymentPayload(challenge));
    res = await fetch(url, { ...init, headers: { ...init.headers, "PAYMENT-SIGNATURE": sig } });
  }
  return res.json();
}

const BASE_URL = "https://stockwaves.net";
const pulse = await pay(`${BASE_URL}/api/cn/trending?platform=all&limit=20`); // ~$0.03 USDC -- China hot-search pulse
const gate  = await pay(`${BASE_URL}/api/xstock/health?symbol=AAPLx`);        // ~$0.03 -- REAL token vs copycat
const free  = await (await fetch(`${BASE_URL}/api/xstock/health/preview?symbol=NVDAx`)).json(); // FREE preview
